import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface NavItem {
  label: string;
  href: string;
}

export interface Experiment {
  id: string;
  title: string;
  description: string;
  status: 'In Development' | 'Internal Alpha' | 'Production Ready';
  icon: string;
}

export interface GrowthStrategyResponse {
  summary: string;
  steps: string[];
  toolsSuggested: string[];
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateGrowthStrategy = async (businessType: string, goal: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a brief, high-level AI-powered growth infrastructure strategy for a ${businessType} aiming to ${goal}. 
      Act as the APXLBS Head of Research. Focus on 'Lab-born' solutions—tools that an engineering-first agency would build for themselves first.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "A high-level summary of the lab-born approach." },
            steps: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "3-4 actionable steps for building growth infrastructure."
            },
            toolsSuggested: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Specific types of AI tools or internal frameworks to deploy."
            }
          },
          required: ["summary", "steps", "toolsSuggested"]
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Error:", error);
    return null;
  }
};

