import React, { useState } from 'react';
import { generateGrowthStrategy } from '../services/geminiService';
import { GrowthStrategyResponse } from '../types';
import { Send, Loader2, Sparkles, AlertCircle } from 'lucide-react';

const StrategyBuilder: React.FC = () => {
  const [business, setBusiness] = useState('');
  const [goal, setGoal] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<GrowthStrategyResponse | null>(null);

  const handleGenerate = async () => {
    if (!business || !goal) return;
    setLoading(true);
    const data = await generateGrowthStrategy(business, goal);
    setResult(data);
    setLoading(false);
  };

  return (
    <section id="infra" className="py-24 px-6 bg-zinc-950 border-y border-white/5">
      <div className="max-w-4xl mx-auto text-center mb-16">
        <h2 className="text-4xl font-black mb-6 tracking-tight">VIRTUAL CONSULTANT</h2>
        <p className="text-gray-400">Enter your core metrics and let our lab-trained AI draft an initial infrastructure map for you.</p>
      </div>

      <div className="max-w-3xl mx-auto glass p-8 rounded-3xl border border-white/10 shadow-2xl">
        <div className="space-y-6">
          <div className="grid md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] mono text-gray-500 uppercase">Industry / Business Model</label>
              <input 
                type="text" 
                placeholder="e.g. B2B SaaS" 
                className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-cyan-400 transition-colors"
                value={business}
                onChange={(e) => setBusiness(e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] mono text-gray-500 uppercase">Primary Growth Goal</label>
              <input 
                type="text" 
                placeholder="e.g. 2x Monthly Leads" 
                className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-cyan-400 transition-colors"
                value={goal}
                onChange={(e) => setGoal(e.target.value)}
              />
            </div>
          </div>

          <button 
            onClick={handleGenerate}
            disabled={loading || !business || !goal}
            className="w-full py-4 bg-gradient-to-r from-cyan-500 to-purple-600 rounded-xl font-bold flex items-center justify-center space-x-2 hover:opacity-90 disabled:opacity-50 transition-all"
          >
            {loading ? <Loader2 className="animate-spin" /> : <Sparkles className="w-5 h-5" />}
            <span>GENERATE INFRASTRUCTURE MAP</span>
          </button>
        </div>

        {result && (
          <div className="mt-12 p-8 bg-white/5 rounded-2xl border border-white/10 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex items-center space-x-2 text-cyan-400 mb-4">
              <AlertCircle className="w-4 h-4" />
              <span className="text-xs mono uppercase tracking-widest">Lab Report Generated</span>
            </div>
            <h4 className="text-2xl font-bold mb-4">Executive Summary</h4>
            <p className="text-gray-400 mb-8 leading-relaxed italic border-l-2 border-purple-500 pl-4">
              "{result.summary}"
            </p>

            <div className="grid md:grid-cols-2 gap-8">
              <div>
                <h5 className="text-[10px] mono text-gray-500 uppercase mb-4 tracking-tighter">Growth Steps</h5>
                <ul className="space-y-3">
                  {result.steps.map((step, idx) => (
                    <li key={idx} className="text-sm flex items-start space-x-3">
                      <span className="text-cyan-400 mt-1 font-bold">{idx + 1}.</span>
                      <span>{step}</span>
                    </li>
                  ))}
                </ul>
              </div>
              <div>
                <h5 className="text-[10px] mono text-gray-500 uppercase mb-4 tracking-tighter">Tools Suggested</h5>
                <div className="flex flex-wrap gap-2">
                  {result.toolsSuggested.map((tool, idx) => (
                    <span key={idx} className="px-3 py-1 bg-white/5 border border-white/10 rounded-full text-xs text-purple-300">
                      {tool}
                    </span>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </section>
  );
};

export default StrategyBuilder;

