              <h3 className="text-3xl font-black mb-4 group-hover:text-[#D4FF00] transition-colors uppercase">JOIN THE LAB</h3>
              <p className="text-gray-400 mb-8 leading-relaxed">
                Are you an engineer or strategist looking to build growth tech that actually works? We're always looking for new minds for the internal lab team.
              </p>
              <button className="text-sm mono font-bold border-b border-white pb-1 hover:border-[#D4FF00] hover:text-[#D4FF00] transition-all">
                EXPLORE CAREERS &rarr;
              </button>
            </div>
          </div>
        </section>
      </main>

      <Footer />
    </div>
  );
};

export default App;

import React, { useEffect, useState, useRef } from 'react';
import { motion, useInView, animate } from 'framer-motion';
import { Quote, CheckCircle2 } from 'lucide-react';

interface MetricValue {
  value: number;
  suffix: string;
  decimals?: number;
}

const testimonials = [
  {
    quote: "The infrastructure APXLBS built for us isn't just a marketing tool; it's a balance sheet asset. Our CAC dropped by 62% in the first quarter of deployment. This is the outlier performance we needed.",
    name: "Alex Rivers",
    title: "Chief Marketing Officer",
    company: "FinScale",
    metric: { value: 62, suffix: "% CAC Reduction" }
  },
  {
    quote: "We stopped hiring more managers and started deploying more agents. The LABS team understands growth as an engineering challenge, not a creative one. Their autonomous pipelines are miles ahead of any agency we've seen.",
    name: "Sarah Chen",
    title: "Founder & CEO",
    company: "Veloce AI",
    metric: { value: 4.2, suffix: "x Lead Velocity", decimals: 1 }
  },
  {
    quote: "Results were guaranteed, but the speed of deployment was what surprised us. We went from manual chaos to a fully autonomous growth machine in 6 weeks. It's the unfair advantage we were looking for.",
    name: "Marcus Thorne",
    title: "Head of Growth",
    company: "Zenith Systems",
    metric: { value: 0, suffix: " Manual Ops" } // "Zero Manual Ops" represented as 0
  }
];

const CountUp: React.FC<{ metric: MetricValue }> = ({ metric }) => {
  const [displayValue, setDisplayValue] = useState(0);
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: "-100px" });

  useEffect(() => {
    if (isInView) {
      const controls = animate(0, metric.value, {
        duration: 2,
        ease: [0.16, 1, 0.3, 1],
        onUpdate: (latest) => {
          setDisplayValue(latest);
        },
      });
      return () => controls.stop();
    }
  }, [isInView, metric.value]);

  return (
    <span ref={ref}>
      {metric.value === 0 && metric.suffix.includes("Manual") ? "Zero" : displayValue.toFixed(metric.decimals || 0)}
      {metric.suffix}
    </span>
  );
};

const Testimonials: React.FC = () => {
  return (
    <section id="results" className="py-32 px-6 bg-black relative overflow-hidden">
      {/* Decorative background element */}
      <div className="mesh-glow top-1/2 left-0 -translate-y-1/2 opacity-10" style={{ background: 'radial-gradient(circle, rgba(212, 255, 0, 0.1) 0%, transparent 70%)' }}></div>

