            FIELD REPORTS.
          </h3>
          <p className="text-gray-500 max-w-2xl text-xl font-medium leading-relaxed">
            Proprietary growth systems deployed across global markets. 
            Proven in the lab, validated by the bottom line.
          </p>
        </div>

        <div className="grid md:grid-cols-3 gap-8">
          {testimonials.map((t, i) => (
            <motion.div
              key={i}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.1, duration: 0.6 }}
              viewport={{ once: true }}
              whileHover={{ y: -8 }}
              className="glaido-card p-10 flex flex-col justify-between group h-full border-white/5 hover:border-[#D4FF00]/20"
            >
              <div>
                <div className="mb-8 flex justify-between items-start">
                  <div className="w-10 h-10 bg-[#D4FF00]/10 rounded-lg flex items-center justify-center">
                    <Quote className="w-5 h-5 text-[#D4FF00]" />
                  </div>
                  <div className="flex items-center space-x-1 text-[#D4FF00] bg-[#D4FF00]/5 px-3 py-1 rounded-full border border-[#D4FF00]/10">
                    <CheckCircle2 className="w-3 h-3" />
                    <span className="text-[10px] mono font-bold uppercase tracking-wider">Verified Asset</span>
                  </div>
                </div>

                <p className="text-gray-300 text-lg leading-relaxed font-medium mb-10 italic">
                  "{t.quote}"
                </p>
              </div>

              <div>
                <div className="mb-6">
                  <div className="text-[10px] mono text-[#D4FF00] font-bold uppercase tracking-widest mb-1">Impact Metric</div>
                  <div className="text-2xl font-black text-white tracking-tight">
                    <CountUp metric={t.metric} />
                  </div>
                </div>

                <div className="pt-6 border-t border-white/5">
                  <div className="text-white font-bold tracking-tight">{t.name}</div>
                  <div className="text-xs text-gray-500 mono uppercase tracking-wider mt-1">
                    {t.title} <span className="text-[#D4FF00]/50 mx-1">—</span> {t.company}
                  </div>
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
};

