import React, { useState } from 'react';
import { generateGrowthStrategy } from '../services/geminiService';
import { GrowthStrategyResponse } from '../types';
import { Loader2, Sparkles, AlertCircle, Terminal, CheckCircle2, AlertTriangle, RefreshCw } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const StrategyBuilder: React.FC = () => {
  const [business, setBusiness] = useState('');
  const [goal, setGoal] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<GrowthStrategyResponse | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  const handleGenerate = async () => {
    if (!business || !goal) return;

    setLoading(true);
    setError(null);
    setShowFeedback(false);

    const data = await generateGrowthStrategy(business, goal);

    setLoading(false);
    if (data) {
      setResult(data);
      setShowFeedback(true);
      // Auto-hide success notification after 5 seconds but keep the result
      setTimeout(() => setShowFeedback(false), 5000);
    } else {
      setError('Communication with the Lab was interrupted. Please check your connection and try again.');
    }
  };

  const handleReset = () => {
    setBusiness('');
    setGoal('');
    setResult(null);
    setError(null);
    setShowFeedback(false);
  };

  return (
    <section id="infra" className="py-32 px-6 bg-black relative border-y border-white/5 overflow-hidden">
      <div className="mesh-glow bottom-[-30%] left-[-10%] opacity-20" style={{ background: 'radial-gradient(circle, rgba(212, 255, 0, 0.1) 0%, transparent 70%)' }}></div>

      <div className="max-w-4xl mx-auto text-center mb-20 relative z-10">
        <h2 className="text-sm mono text-[#D4FF00] mb-6 uppercase tracking-[0.4em] font-bold">// THE ARCHITECT</h2>
        <h3 className="text-5xl md:text-7xl font-extrabold tracking-tighter mb-8 glaido-gradient">BUILD YOUR MAP.</h3>
        <p className="text-gray-500 text-xl font-medium">Use our internal lab-trained model to simulate your growth infrastructure.</p>
      </div>

      <div className="max-w-3xl mx-auto relative z-10">
        <div className="glaido-card p-12 border-white/10 shadow-2xl bg-zinc-950/40">
          <div className="space-y-8">
            <div className="grid md:grid-cols-2 gap-8">
              <div className="space-y-3">
                <label className="text-[10px] mono text-gray-500 uppercase font-bold tracking-widest flex items-center">
                  <Terminal className="w-3 h-3 mr-2 text-[#D4FF00]" /> Sector / Business
                </label>
                <input 
                  type="text" 
                  placeholder="e.g. Fintech" 
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-5 py-4 focus:outline-none focus:border-[#D4FF00] transition-all text-white placeholder:text-gray-700 font-medium disabled:opacity-50"
                  value={business}
                  onChange={(e) => setBusiness(e.target.value)}
                  disabled={loading}
                />
              </div>
              <div className="space-y-3">
                <label className="text-[10px] mono text-gray-500 uppercase font-bold tracking-widest flex items-center">
                  <Terminal className="w-3 h-3 mr-2 text-[#D4FF00]" /> Core Objective
                </label>
                <input 
                  type="text" 
                  placeholder="e.g. 500 New Accounts" 
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-5 py-4 focus:outline-none focus:border-[#D4FF00] transition-all text-white placeholder:text-gray-700 font-medium disabled:opacity-50"
                  value={goal}
                  onChange={(e) => setGoal(e.target.value)}
                  disabled={loading}
                />
              </div>
            </div>

            <div className="flex space-x-4">
              <button 
                onClick={handleGenerate}
                disabled={loading || !business || !goal}
                className="flex-grow py-5 bg-white text-black rounded-2xl font-black flex items-center justify-center space-x-3 hover:bg-[#D4FF00] transition-all disabled:opacity-30 text-lg shadow-[0_0_20px_rgba(255,255,255,0.05)]"
              >
                {loading ? <Loader2 className="animate-spin w-6 h-6" /> : <Sparkles className="w-6 h-6" />}
                <span className="uppercase tracking-tighter">{loading ? 'Processing Data...' : 'GENERATE DEPLOYMENT LOGS'}</span>
              </button>

              {result && !loading && (
                <button 
                  onClick={handleReset}
                  className="px-6 bg-white/5 border border-white/10 rounded-2xl flex items-center justify-center hover:bg-white/10 transition-all text-white"
                  title="New Simulation"
                >
                  <RefreshCw className="w-6 h-6" />
                </button>
              )}
            </div>
          </div>

          <AnimatePresence>
            {error && (
              <motion.div 
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                className="mt-6 p-4 bg-red-500/10 border border-red-500/20 rounded-xl flex items-center space-x-3 text-red-400"
              >
                <AlertTriangle className="w-5 h-5 flex-shrink-0" />
                <span className="text-sm font-medium">{error}</span>
              </motion.div>
            )}

            {showFeedback && (
              <motion.div 
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                className="mt-6 p-4 bg-[#D4FF00]/10 border border-[#D4FF00]/20 rounded-xl flex items-center space-x-3 text-[#D4FF00]"
              >
                <CheckCircle2 className="w-5 h-5 flex-shrink-0" />
                <span className="text-sm font-bold uppercase tracking-widest mono">Deployment Logs Successfully Compiled</span>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        {result && (
          <motion.div 
            initial={{ opacity: 0, y: 40 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
            className="mt-16 p-10 bg-black rounded-3xl border border-white/10 relative overflow-hidden"
          >
            <div className="absolute top-0 right-0 p-4">
               <div className="flex items-center space-x-2 text-[#D4FF00] bg-[#D4FF00]/5 px-3 py-1 rounded-full border border-[#D4FF00]/10">
                  <span className="w-2 h-2 bg-[#D4FF00] rounded-full animate-pulse"></span>
                  <span className="text-[10px] mono font-bold uppercase tracking-widest">Live Output</span>
               </div>
            </div>

            <div className="flex items-center space-x-2 text-gray-500 mb-6">
              <AlertCircle className="w-4 h-4 text-[#D4FF00]" />
              <span className="text-xs mono uppercase tracking-widest font-bold">Lab Report Status: Online</span>
            </div>

            <h4 className="text-3xl font-extrabold mb-6 tracking-tight">Executive Summary</h4>
            <p className="text-gray-400 mb-10 text-lg leading-relaxed italic border-l-4 border-[#D4FF00] pl-6">
              "{result.summary}"
            </p>

            <div className="grid md:grid-cols-2 gap-12">
              <motion.div
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.2 }}
              >
                <h5 className="text-[11px] mono text-gray-500 uppercase mb-6 tracking-widest font-bold flex items-center">
                  <div className="w-4 h-4 rounded bg-[#D4FF00]/10 flex items-center justify-center mr-2">
                    <Terminal className="w-2.5 h-2.5 text-[#D4FF00]" />
                  </div>
                  Deployment Roadmap
                </h5>
                <ul className="space-y-4">
                  {result.steps.map((step, idx) => (
                    <li key={idx} className="text-[15px] flex items-start space-x-4 group">
                      <span className="text-[#D4FF00] font-black mono text-xs mt-1">0{idx + 1}</span>
                      <span className="text-gray-300 group-hover:text-white transition-colors">{step}</span>
                    </li>
                  ))}
                </ul>
              </motion.div>

              <motion.div
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.4 }}
              >
                <h5 className="text-[11px] mono text-gray-500 uppercase mb-6 tracking-widest font-bold flex items-center">
                   <div className="w-4 h-4 rounded bg-[#D4FF00]/10 flex items-center justify-center mr-2">
                    <Sparkles className="w-2.5 h-2.5 text-[#D4FF00]" />
                  </div>
                  Recommended Assets
                </h5>
                <div className="flex flex-wrap gap-3">
                  {result.toolsSuggested.map((tool, idx) => (
                    <span key={idx} className="px-4 py-2 bg-white/5 border border-white/10 rounded-xl text-xs text-[#D4FF00] font-bold tracking-tight hover:bg-white/10 hover:border-[#D4FF00]/30 transition-all cursor-default">
                      {tool}
                    </span>
                  ))}
                </div>
              </motion.div>
            </div>

            <div className="mt-12 pt-8 border-t border-white/5 flex justify-between items-center text-[10px] mono text-gray-600">
              <div className="uppercase tracking-widest">Hash: {Math.random().toString(36).substring(7).toUpperCase()}</div>
              <div className="flex items-center space-x-2">
                <span className="uppercase">Ready for deployment</span>
                <CheckCircle2 className="w-3 h-3 text-[#D4FF00]" />
              </div>
            </div>
          </motion.div>
        )}
      </div>
    </section>
  );
};

export default StrategyBuilder;

