import React, { useEffect, useRef } from 'react';

interface CardScannerSectionProps {
  hideText?: boolean;
}

const CardScannerSection: React.FC<CardScannerSectionProps> = ({ hideText = false }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const cardLineRef = useRef<HTMLDivElement>(null);
  const particleCanvasRef = useRef<HTMLCanvasElement>(null);
  const scannerCanvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number | null>(null);

  useEffect(() => {
    if (!containerRef.current || !cardLineRef.current || !particleCanvasRef.current || !scannerCanvasRef.current) return;

    const codeChars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789(){}[]<>;:,._-+=!@#$%^&*|\\/\"'`~?";

    class CardStreamController {
      container: HTMLElement;
      cardLine: HTMLElement;
      position: number;
      velocity: number;
      direction: number;
      isAnimating: boolean;
      isDragging: boolean;
      lastTime: number;
      lastMouseX: number;
      mouseVelocity: number;
      friction: number;
      minVelocity: number;
      containerWidth: number;
      cardLineWidth: number;
      scanner: ParticleScanner;

      constructor(container: HTMLElement, cardLine: HTMLElement, scanner: ParticleScanner) {
        this.container = container;
        this.cardLine = cardLine;
        this.scanner = scanner;
        this.position = 0;
        this.velocity = 120;
        this.direction = -1;
        this.isAnimating = true;
        this.isDragging = false;
        this.lastTime = performance.now();
        this.lastMouseX = 0;
        this.mouseVelocity = 0;
        this.friction = 0.95;
        this.minVelocity = 40;
        this.containerWidth = 0;
        this.cardLineWidth = 0;
        this.init();
      }

      init() {
        this.populateCardLine();
        this.calculateDimensions();
        this.setupEventListeners();
      }

      calculateDimensions() {
        this.containerWidth = this.container.offsetWidth;
        const cardWidth = 400;
        const cardGap = 60;
        const cardCount = this.cardLine.children.length;
        this.cardLineWidth = (cardWidth + cardGap) * cardCount;
      }

      setupEventListeners() {
        const handleMouseDown = (e: MouseEvent) => this.startDrag(e);
        const handleMouseMove = (e: MouseEvent) => this.onDrag(e);
        const handleMouseUp = () => this.endDrag();
        const handleResize = () => this.calculateDimensions();

        this.cardLine.addEventListener("mousedown", handleMouseDown);
        window.addEventListener("mousemove", handleMouseMove);
        window.addEventListener("mouseup", handleMouseUp);
        window.addEventListener("resize", handleResize);

        return () => {
          this.cardLine.removeEventListener("mousedown", handleMouseDown);
          window.removeEventListener("mousemove", handleMouseMove);
          window.removeEventListener("mouseup", handleMouseUp);
          window.removeEventListener("resize", handleResize);
        };
      }

      startDrag(e: MouseEvent) {
        this.isDragging = true;
        this.isAnimating = false;
        this.lastMouseX = e.clientX;
        this.mouseVelocity = 0;
      }

      onDrag(e: MouseEvent) {
        if (!this.isDragging) return;
        const deltaX = e.clientX - this.lastMouseX;
        this.position += deltaX;
        this.mouseVelocity = deltaX * 60;
        this.lastMouseX = e.clientX;
        this.updateCardPosition(false);
      }

      endDrag() {
        if (!this.isDragging) return;
        this.isDragging = false;
        if (Math.abs(this.mouseVelocity) > this.minVelocity) {
          this.velocity = Math.min(Math.abs(this.mouseVelocity), 1000);
          this.direction = this.mouseVelocity > 0 ? 1 : -1;
        } else {
          this.velocity = 120;
        }
        this.isAnimating = true;
      }

      tick() {
        const currentTime = performance.now();
        const deltaTime = (currentTime - this.lastTime) / 1000;
        this.lastTime = currentTime;

        if (this.isAnimating && !this.isDragging) {
          if (this.velocity > this.minVelocity) {
            this.velocity *= Math.pow(this.friction, deltaTime * 60);
          } else {
            this.velocity = this.minVelocity;
          }
          this.position += this.velocity * this.direction * deltaTime;
          this.updateCardPosition(true);
        }
      }

      updateCardPosition(isAuto: boolean) {
        if (this.position < -this.cardLineWidth) {
          this.position = this.containerWidth;
        } else if (this.position > this.containerWidth) {
          this.position = -this.cardLineWidth;
        }
        this.cardLine.style.transform = `translateX(${this.position}px)`;
        this.updateCardClipping();
      }

      updateCardClipping() {
        const scannerX = window.innerWidth / 2;
        let anyScanningActive = false;

        const wrappers = this.cardLine.querySelectorAll(".card-wrapper");
        wrappers.forEach((wrapper) => {
          const rect = wrapper.getBoundingClientRect();
          const cardLeft = rect.left;
          const cardRight = rect.right;
          const cardWidth = rect.width;

          const normalCard = wrapper.querySelector(".card-normal") as HTMLElement;
          const asciiCard = wrapper.querySelector(".card-ascii") as HTMLElement;

          if (cardLeft < scannerX && cardRight > scannerX) {
            anyScanningActive = true;
            // The percentage of the card that has passed the scanner line (from left to right)
            const passedAmount = scannerX - cardLeft;
            const clipPercent = Math.max(0, Math.min(100, (passedAmount / cardWidth) * 100));

            // Visual Card: Clip its RIGHT side away as it moves past the center line.
            // ASCII Card: Reveal only the RIGHT part as it moves past the center line.
            wrapper.style.setProperty("--clip-amount", `${100 - clipPercent}%`);

            if (!wrapper.hasAttribute("data-scanned")) {
              wrapper.setAttribute("data-scanned", "true");
              const scanEffect = document.createElement("div");
              scanEffect.className = "scan-effect";
              wrapper.appendChild(scanEffect);
              setTimeout(() => scanEffect.remove(), 600);
            }
          } else {
            if (cardRight <= scannerX) {
              // Card is fully to the left of the scanner -> Reveal 0% of ASCII (fully Visual)
              // Wait, the logic is visual-on-left, code-on-right.
              // If cardRight < scannerX, it's fully to the left of the line. Should be Visual.
              // clip-amount = 0% -> normal clips 0% (full visual), ascii clips 100% (hidden)
              wrapper.style.setProperty("--clip-amount", `0%`);
            } else if (cardLeft >= scannerX) {
              // Card is fully to the right of the scanner -> Fully ASCII.
              // clip-amount = 100% -> normal clips 100% (hidden), ascii clips 0% (full ascii)
              wrapper.style.setProperty("--clip-amount", `100%`);
            }
            wrapper.removeAttribute("data-scanned");
          }
        });

        this.scanner.scanningActive = anyScanningActive;
      }

      generateCode(width: number, height: number) {
        const randInt = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;
        let flow = "";
        for (let i = 0; i < height; i++) {
          let line = "";
          for (let j = 0; j < width; j++) {
            line += codeChars[randInt(0, codeChars.length - 1)];
          }
          flow += line + (i < height - 1 ? "\n" : "");
        }
        return flow;
      }

      createCardWrapper(index: number) {
        const wrapper = document.createElement("div");
        wrapper.className = "card-wrapper";
        const cardImages = [
          "https://cdn.prod.website-files.com/68789c86c8bc802d61932544/689f20b55e654d1341fb06f8_4.1.png",
          "https://cdn.prod.website-files.com/68789c86c8bc802d61932544/689f20b5a080a31ee7154b19_1.png",
          "https://cdn.prod.website-files.com/68789c86c8bc802d61932544/689f20b5c1e4919fd69672b8_3.png",
          "https://cdn.prod.website-files.com/68789c86c8bc802d61932544/689f20b5f6a5e232e7beb4be_2.png"
        ];

        const normalCard = document.createElement("div");
        normalCard.className = "card card-normal";
        const img = document.createElement("img");
        img.src = cardImages[index % cardImages.length];
        img.className = "card-image";
        img.draggable = false;
        normalCard.appendChild(img);

        const asciiCard = document.createElement("div");
        asciiCard.className = "card card-ascii";
        const content = document.createElement("div");
        content.className = "ascii-content";
        content.textContent = this.generateCode(65, 18);
        asciiCard.appendChild(content);

        wrapper.appendChild(normalCard);
        wrapper.appendChild(asciiCard);
        return wrapper;
      }

      populateCardLine() {
        this.cardLine.innerHTML = "";
        for (let i = 0; i < 20; i++) {
          this.cardLine.appendChild(this.createCardWrapper(i));
        }
      }
    }

    class ParticleScanner {
      canvas: HTMLCanvasElement;
      ctx: CanvasRenderingContext2D;
      w: number;
      h: number;
      lightBarX: number;
      scanningActive: boolean;

      constructor(canvas: HTMLCanvasElement) {
        this.canvas = canvas;
        this.ctx = canvas.getContext("2d")!;
        this.w = window.innerWidth;
        this.h = 300;
        this.lightBarX = this.w / 2;
        this.scanningActive = false;
        this.init();
      }

      init() {
        this.canvas.width = this.w;
        this.canvas.height = this.h;
        window.addEventListener("resize", () => {
          this.w = window.innerWidth;
          this.lightBarX = this.w / 2;
          this.canvas.width = this.w;
        });
      }

      tick() {
        this.ctx.clearRect(0, 0, this.w, this.h);
        this.drawScanner();
      }

      drawScanner() {
        const x = this.lightBarX;
        const grad = this.ctx.createLinearGradient(x - 8, 0, x + 8, 0);
        grad.addColorStop(0, "rgba(212, 255, 0, 0)");
        grad.addColorStop(0.5, this.scanningActive ? "rgba(212, 255, 0, 0.8)" : "rgba(255, 255, 255, 0.3)");
        grad.addColorStop(1, "rgba(212, 255, 0, 0)");

        this.ctx.fillStyle = grad;
        this.ctx.fillRect(x - 6, 0, 12, this.h);

        if (this.scanningActive) {
          this.ctx.shadowBlur = 15;
          this.ctx.shadowColor = "#D4FF00";
          this.ctx.fillStyle = "#D4FF00";
          this.ctx.fillRect(x - 1, 0, 2, this.h);
          this.ctx.shadowBlur = 0;
        }
      }
    }

    // Three.js Simplified Background
    let points: any;
    let renderer: any;
    let scene: any;
    let camera: any;

    const initThree = () => {
      const THREE = (window as any).THREE;
      if (!THREE) return;
      scene = new THREE.Scene();
      camera = new THREE.OrthographicCamera(-window.innerWidth/2, window.innerWidth/2, 125, -125, 1, 1000);
      renderer = new THREE.WebGLRenderer({ canvas: particleCanvasRef.current!, alpha: true, antialias: true });
      renderer.setSize(window.innerWidth, 250);

      const geometry = new THREE.BufferGeometry();
      const count = 300;
      const pos = new Float32Array(count * 3);
      for(let i=0; i<count*3; i++) {
        pos[i*3] = (Math.random()-0.5)*2000;
        pos[i*3+1] = (Math.random()-0.5)*250;
        pos[i*3+2] = 0;
      }
      geometry.setAttribute('position', new THREE.BufferAttribute(pos, 3));
      const material = new THREE.PointsMaterial({ color: 0xD4FF00, size: 2, transparent: true, opacity: 0.2 });
      points = new THREE.Points(geometry, material);
      scene.add(points);
    };

    initThree();
    const scanner = new ParticleScanner(scannerCanvasRef.current);
    const stream = new CardStreamController(containerRef.current, cardLineRef.current, scanner);

    const mainLoop = () => {
      stream.tick();
      scanner.tick();
      if (renderer && scene && camera && points) {
        points.rotation.y += 0.0005;
        renderer.render(scene, camera);
      }
      animationRef.current = requestAnimationFrame(mainLoop);
    };

    mainLoop();

    // Ascii Glitch update
    const glitchInterval = setInterval(() => {
        document.querySelectorAll(".ascii-content").forEach(content => {
            if (Math.random() < 0.05) {
                content.textContent = stream.generateCode(65, 18);
            }
        });
    }, 200);

    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      clearInterval(glitchInterval);
      if (renderer) renderer.dispose();
    };
  }, []);

  return (
    <div className={`scanner-section-container ${hideText ? 'h-[450px]' : 'py-24'}`}>
      {!hideText && (
        <div className="max-w-4xl mx-auto text-center mb-16 relative z-20">
          <h2 className="text-4xl md:text-7xl font-black mb-6 tracking-tight text-white">
            Stop Burning Cash on <br />
            <span className="text-[#D4FF00]">Bad Websites</span>
          </h2>
          <p className="text-gray-400 text-lg md:text-xl font-medium max-w-2xl mx-auto px-6">
            We scan your business and reveal the hidden code to high-converting websites—without the expensive trial and error.
          </p>
        </div>
      )}

      <div className="relative w-full h-[300px] flex items-center justify-center cursor-grab active:cursor-grabbing" ref={containerRef}>
        <canvas id="particleCanvas" ref={particleCanvasRef} className="absolute inset-0 w-full h-full"></canvas>
        <canvas id="scannerCanvas" ref={scannerCanvasRef} className="absolute inset-0 w-full h-full"></canvas>
        <div className="card-stream">
          <div className="card-line" ref={cardLineRef}></div>
        </div>
      </div>
    </div>
  );
};

export default CardScannerSection;

import React, { useEffect, useRef } from 'react';

interface CardScannerSectionProps {
  hideText?: boolean;
}

const CardScannerSection: React.FC<CardScannerSectionProps> = ({ hideText = false }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const cardLineRef = useRef<HTMLDivElement>(null);
  const particleCanvasRef = useRef<HTMLCanvasElement>(null);
  const scannerCanvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number | null>(null);

  useEffect(() => {
    if (!containerRef.current || !cardLineRef.current || !particleCanvasRef.current || !scannerCanvasRef.current) return;

    const codeChars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789(){}[]<>;:,._-+=!@#$%^&*|\\/\"'`~?";

    class CardStreamController {
      container: HTMLElement;
      cardLine: HTMLElement;
      position: number;
      velocity: number;
      direction: number;
      isAnimating: boolean;
      isDragging: boolean;
      lastTime: number;
      lastMouseX: number;
      mouseVelocity: number;
      friction: number;
      minVelocity: number;
      containerWidth: number;
      cardLineWidth: number;
      scanner: ParticleScanner;

      constructor(container: HTMLElement, cardLine: HTMLElement, scanner: ParticleScanner) {
        this.container = container;
        this.cardLine = cardLine;
        this.scanner = scanner;
        this.position = 0;
        this.velocity = 120;
        this.direction = -1;
        this.isAnimating = true;
        this.isDragging = false;
        this.lastTime = performance.now();
        this.lastMouseX = 0;
        this.mouseVelocity = 0;
        this.friction = 0.95;
        this.minVelocity = 40;
        this.containerWidth = 0;
        this.cardLineWidth = 0;
        this.init();
      }

      init() {
        this.populateCardLine();
        this.calculateDimensions();
        this.setupEventListeners();
      }

      calculateDimensions() {
        this.containerWidth = this.container.offsetWidth;
        const cardWidth = 400;
        const cardGap = 60;
        const cardCount = this.cardLine.children.length;
        this.cardLineWidth = (cardWidth + cardGap) * cardCount;
      }

      setupEventListeners() {
        const handleMouseDown = (e: MouseEvent) => this.startDrag(e);
        const handleMouseMove = (e: MouseEvent) => this.onDrag(e);
        const handleMouseUp = () => this.endDrag();
        const handleResize = () => this.calculateDimensions();

        this.cardLine.addEventListener("mousedown", handleMouseDown);
        window.addEventListener("mousemove", handleMouseMove);
        window.addEventListener("mouseup", handleMouseUp);
        window.addEventListener("resize", handleResize);

        return () => {
          this.cardLine.removeEventListener("mousedown", handleMouseDown);
          window.removeEventListener("mousemove", handleMouseMove);
          window.removeEventListener("mouseup", handleMouseUp);
          window.removeEventListener("resize", handleResize);
        };
      }

      startDrag(e: MouseEvent) {
        this.isDragging = true;
        this.isAnimating = false;
        this.lastMouseX = e.clientX;
        this.mouseVelocity = 0;
      }

      onDrag(e: MouseEvent) {
        if (!this.isDragging) return;
        const deltaX = e.clientX - this.lastMouseX;
        this.position += deltaX;
        this.mouseVelocity = deltaX * 60;
        this.lastMouseX = e.clientX;
        this.updateCardPosition(false);
      }

      endDrag() {
        if (!this.isDragging) return;
        this.isDragging = false;
        if (Math.abs(this.mouseVelocity) > this.minVelocity) {
          this.velocity = Math.min(Math.abs(this.mouseVelocity), 1000);
          this.direction = this.mouseVelocity > 0 ? 1 : -1;
        } else {
          this.velocity = 120;
        }
        this.isAnimating = true;
      }

      tick() {
        const currentTime = performance.now();
        const deltaTime = (currentTime - this.lastTime) / 1000;
        this.lastTime = currentTime;

        if (this.isAnimating && !this.isDragging) {
          if (this.velocity > this.minVelocity) {
            this.velocity *= Math.pow(this.friction, deltaTime * 60);
          } else {
            this.velocity = this.minVelocity;
          }
          this.position += this.velocity * this.direction * deltaTime;
          this.updateCardPosition(true);
        }
      }

      updateCardPosition(isAuto: boolean) {
        if (this.position < -this.cardLineWidth) {
          this.position = this.containerWidth;
        } else if (this.position > this.containerWidth) {
          this.position = -this.cardLineWidth;
        }
        this.cardLine.style.transform = `translateX(${this.position}px)`;
        this.updateCardClipping();
      }

      updateCardClipping() {
        const scannerX = window.innerWidth / 2;
        let anyScanningActive = false;

        const wrappers = this.cardLine.querySelectorAll(".card-wrapper");
        // FIX: Explicitly cast to HTMLElement to resolve 'Property style does not exist on type Element' errors
        wrappers.forEach((el) => {
          const wrapper = el as HTMLElement;
          const rect = wrapper.getBoundingClientRect();
          const cardLeft = rect.left;
          const cardRight = rect.right;
          const cardWidth = rect.width;

          const normalCard = wrapper.querySelector(".card-normal") as HTMLElement;
          const asciiCard = wrapper.querySelector(".card-ascii") as HTMLElement;

          if (cardLeft < scannerX && cardRight > scannerX) {
            anyScanningActive = true;
            // The percentage of the card that has passed the scanner line (from left to right)
            const passedAmount = scannerX - cardLeft;
            const clipPercent = Math.max(0, Math.min(100, (passedAmount / cardWidth) * 100));

            // Visual Card: Clip its RIGHT side away as it moves past the center line.
            // ASCII Card: Reveal only the RIGHT part as it moves past the center line.
            wrapper.style.setProperty("--clip-amount", `${100 - clipPercent}%`);

            if (!wrapper.hasAttribute("data-scanned")) {
              wrapper.setAttribute("data-scanned", "true");
              const scanEffect = document.createElement("div");
              scanEffect.className = "scan-effect";
              wrapper.appendChild(scanEffect);
              setTimeout(() => scanEffect.remove(), 600);
            }
          } else {
            if (cardRight <= scannerX) {
              // Card is fully to the left of the scanner -> Reveal 0% of ASCII (fully Visual)
              // Wait, the logic is visual-on-left, code-on-right.
              // If cardRight < scannerX, it's fully to the left of the line. Should be Visual.
              // clip-amount = 0% -> normal clips 0% (full visual), ascii clips 100% (hidden)
              wrapper.style.setProperty("--clip-amount", `0%`);
            } else if (cardLeft >= scannerX) {
              // Card is fully to the right of the scanner -> Fully ASCII.
              // clip-amount = 100% -> normal clips 100% (hidden), ascii clips 0% (full ascii)
              wrapper.style.setProperty("--clip-amount", `100%`);
            }
            wrapper.removeAttribute("data-scanned");
          }
        });

        this.scanner.scanningActive = anyScanningActive;
      }

      generateCode(width: number, height: number) {
        const randInt = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;
        let flow = "";
        for (let i = 0; i < height; i++) {
          let line = "";
          for (let j = 0; j < width; j++) {
            line += codeChars[randInt(0, codeChars.length - 1)];
          }
          flow += line + (i < height - 1 ? "\n" : "");
        }
        return flow;
      }

      createCardWrapper(index: number) {
        const wrapper = document.createElement("div");
        wrapper.className = "card-wrapper";
        const cardImages = [
          "https://cdn.prod.website-files.com/68789c86c8bc802d61932544/689f20b55e654d1341fb06f8_4.1.png",
          "https://cdn.prod.website-files.com/68789c86c8bc802d61932544/689f20b5a080a31ee7154b19_1.png",
          "https://cdn.prod.website-files.com/68789c86c8bc802d61932544/689f20b5c1e4919fd69672b8_3.png",
          "https://cdn.prod.website-files.com/68789c86c8bc802d61932544/689f20b5f6a5e232e7beb4be_2.png"
        ];

        const normalCard = document.createElement("div");
        normalCard.className = "card card-normal";
        const img = document.createElement("img");
        img.src = cardImages[index % cardImages.length];
        img.className = "card-image";
        img.draggable = false;
        normalCard.appendChild(img);

        const asciiCard = document.createElement("div");
        asciiCard.className = "card card-ascii";
        const content = document.createElement("div");
        content.className = "ascii-content";
        content.textContent = this.generateCode(65, 18);
        asciiCard.appendChild(content);

        wrapper.appendChild(normalCard);
        wrapper.appendChild(asciiCard);
        return wrapper;
      }

      populateCardLine() {
        this.cardLine.innerHTML = "";
        for (let i = 0; i < 20; i++) {
          this.cardLine.appendChild(this.createCardWrapper(i));
        }
      }
    }

    class ParticleScanner {
      canvas: HTMLCanvasElement;
      ctx: CanvasRenderingContext2D;
      w: number;
      h: number;
      lightBarX: number;
      scanningActive: boolean;

      constructor(canvas: HTMLCanvasElement) {
        this.canvas = canvas;
        this.ctx = canvas.getContext("2d")!;
        this.w = window.innerWidth;
        this.h = 300;
        this.lightBarX = this.w / 2;
        this.scanningActive = false;
        this.init();
      }

      init() {
        this.canvas.width = this.w;
        this.canvas.height = this.h;
        window.addEventListener("resize", () => {
          this.w = window.innerWidth;
          this.lightBarX = this.w / 2;
          this.canvas.width = this.w;
        });
      }

      tick() {
        this.ctx.clearRect(0, 0, this.w, this.h);
        this.drawScanner();
      }

      drawScanner() {
        const x = this.lightBarX;
        const grad = this.ctx.createLinearGradient(x - 8, 0, x + 8, 0);
        grad.addColorStop(0, "rgba(212, 255, 0, 0)");
        grad.addColorStop(0.5, this.scanningActive ? "rgba(212, 255, 0, 0.8)" : "rgba(255, 255, 255, 0.3)");
        grad.addColorStop(1, "rgba(212, 255, 0, 0)");

        this.ctx.fillStyle = grad;
        this.ctx.fillRect(x - 6, 0, 12, this.h);

        if (this.scanningActive) {
          this.ctx.shadowBlur = 15;
          this.ctx.shadowColor = "#D4FF00";
          this.ctx.fillStyle = "#D4FF00";
          this.ctx.fillRect(x - 1, 0, 2, this.h);
          this.ctx.shadowBlur = 0;
        }
      }
    }

    // Three.js Simplified Background
    let points: any;
    let renderer: any;
    let scene: any;
    let camera: any;

    const initThree = () => {
      const THREE = (window as any).THREE;
      if (!THREE) return;
      scene = new THREE.Scene();
      camera = new THREE.OrthographicCamera(-window.innerWidth/2, window.innerWidth/2, 125, -125, 1, 1000);
      renderer = new THREE.WebGLRenderer({ canvas: particleCanvasRef.current!, alpha: true, antialias: true });
      renderer.setSize(window.innerWidth, 250);

      const geometry = new THREE.BufferGeometry();
      const count = 300;
      const pos = new Float32Array(count * 3);
      for(let i=0; i<count*3; i++) {
        pos[i*3] = (Math.random()-0.5)*2000;
        pos[i*3+1] = (Math.random()-0.5)*250;
        pos[i*3+2] = 0;
      }
      geometry.setAttribute('position', new THREE.BufferAttribute(pos, 3));
      const material = new THREE.PointsMaterial({ color: 0xD4FF00, size: 2, transparent: true, opacity: 0.2 });
      points = new THREE.Points(geometry, material);
      scene.add(points);
    };

    initThree();
    const scanner = new ParticleScanner(scannerCanvasRef.current);
    const stream = new CardStreamController(containerRef.current, cardLineRef.current, scanner);

    const mainLoop = () => {
      stream.tick();
      scanner.tick();
      if (renderer && scene && camera && points) {
        points.rotation.y += 0.0005;
        renderer.render(scene, camera);
      }
      animationRef.current = requestAnimationFrame(mainLoop);
    };

    mainLoop();

    // Ascii Glitch update
    const glitchInterval = setInterval(() => {
        document.querySelectorAll(".ascii-content").forEach(content => {
            if (Math.random() < 0.05) {
                content.textContent = stream.generateCode(65, 18);
            }
        });
    }, 200);

    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      clearInterval(glitchInterval);
      if (renderer) renderer.dispose();
    };
  }, []);

  return (
    <div className={`scanner-section-container ${hideText ? 'h-[450px]' : 'py-24'}`}>
      {!hideText && (
        <div className="max-w-4xl mx-auto text-center mb-16 relative z-20">
          <h2 className="text-4xl md:text-7xl font-black mb-6 tracking-tight text-white">
            Stop Burning Cash on <br />
            <span className="text-[#D4FF00]">Bad Websites</span>
          </h2>
          <p className="text-gray-400 text-lg md:text-xl font-medium max-w-2xl mx-auto px-6">
            We scan your business and reveal the hidden code to high-converting websites—without the expensive trial and error.
          </p>
        </div>
      )}

      <div className="relative w-full h-[300px] flex items-center justify-center cursor-grab active:cursor-grabbing" ref={containerRef}>
        <canvas id="particleCanvas" ref={particleCanvasRef} className="absolute inset-0 w-full h-full"></canvas>
        <canvas id="scannerCanvas" ref={scannerCanvasRef} className="absolute inset-0 w-full h-full"></canvas>
        <div className="card-stream">
          <div className="card-line" ref={cardLineRef}></div>
        </div>
      </div>
    </div>
  );
};

export default CardScannerSection;

