import React, { useEffect, useRef } from 'react';

interface CardScannerSectionProps {
  hideText?: boolean;
}

const CardScannerSection: React.FC<CardScannerSectionProps> = ({ hideText = false }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const cardLineRef = useRef<HTMLDivElement>(null);
  const cardStreamRef = useRef<HTMLDivElement>(null);
  const particleCanvasRef = useRef<HTMLCanvasElement>(null);
  const scannerCanvasRef = useRef<HTMLCanvasElement>(null);
  const speedValueRef = useRef<HTMLSpanElement>(null);

  useEffect(() => {
    const THREE = (window as any).THREE;
    if (!THREE || !cardLineRef.current || !cardStreamRef.current || !particleCanvasRef.current || !scannerCanvasRef.current) return;

    const codeChars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789(){}[]<>;:,._-+=!@#$%^&*|\\/\"'`~?";

    class CardStreamController {
      container: HTMLElement;
      cardLine: HTMLElement;
      speedIndicator: HTMLElement | null;
      position: number;
      velocity: number;
      direction: number;
      isAnimating: boolean;
      isDragging: boolean;
      lastTime: number;
      lastMouseX: number;
      mouseVelocity: number;
      friction: number;
      minVelocity: number;
      containerWidth: number;
      cardLineWidth: number;
      animationId: number | null = null;

      constructor(container: HTMLElement, cardLine: HTMLElement, speedIndicator: HTMLElement | null) {
        this.container = container;
        this.cardLine = cardLine;
        this.speedIndicator = speedIndicator;
        this.position = 0;
        this.velocity = 120;
        this.direction = -1;
        this.isAnimating = true;
        this.isDragging = false;
        this.lastTime = 0;
        this.lastMouseX = 0;
        this.mouseVelocity = 0;
        this.friction = 0.95;
        this.minVelocity = 30;
        this.containerWidth = 0;
        this.cardLineWidth = 0;
        this.init();
      }

      init() {
        this.populateCardLine();
        this.calculateDimensions();
        this.setupEventListeners();
        this.updateCardPosition();
        this.animate();
        this.startPeriodicUpdates();
      }

      calculateDimensions() {
        this.containerWidth = this.container.offsetWidth;
        const cardWidth = 400;
        const cardGap = 60;
        const cardCount = this.cardLine.children.length;
        this.cardLineWidth = (cardWidth + cardGap) * cardCount;
      }

      setupEventListeners() {
        this.cardLine.addEventListener("mousedown", (e) => this.startDrag(e));
        const onMouseMove = (e: MouseEvent) => this.onDrag(e);
        const onMouseUp = () => this.endDrag();

        window.addEventListener("mousemove", onMouseMove);
        window.addEventListener("mouseup", onMouseUp);

        this.cardLine.addEventListener("touchstart", (e) => this.startDrag(e.touches[0] as any), { passive: false });
        window.addEventListener("touchmove", (e) => this.onDrag(e.touches[0] as any), { passive: false });
        window.addEventListener("touchend", () => this.endDrag());

        window.addEventListener("resize", () => this.calculateDimensions());
      }

      startDrag(e: MouseEvent) {
        e.preventDefault();
        this.isDragging = true;
        this.isAnimating = false;
        this.lastMouseX = e.clientX;
        this.mouseVelocity = 0;
        this.cardLine.classList.add("dragging");
      }

      onDrag(e: MouseEvent) {
        if (!this.isDragging) return;
        const deltaX = e.clientX - this.lastMouseX;
        this.position += deltaX;
        this.mouseVelocity = deltaX * 60;
        this.lastMouseX = e.clientX;
        this.cardLine.style.transform = `translateX(${this.position}px)`;
        this.updateCardClipping();
      }

      endDrag() {
        if (!this.isDragging) return;
        this.isDragging = false;
        this.cardLine.classList.remove("dragging");
        if (Math.abs(this.mouseVelocity) > this.minVelocity) {
          this.velocity = Math.abs(this.mouseVelocity);
          this.direction = this.mouseVelocity > 0 ? 1 : -1;
        } else {
          this.velocity = 120;
        }
        this.isAnimating = true;
        this.updateSpeedIndicator();
      }

      animate() {
        const currentTime = performance.now();
        const deltaTime = (currentTime - this.lastTime) / 1000;
        this.lastTime = currentTime;

        if (this.isAnimating && !this.isDragging) {
          if (this.velocity > this.minVelocity) {
            this.velocity *= this.friction;
          } else {
            this.velocity = Math.max(this.minVelocity, this.velocity);
          }
          this.position += this.velocity * this.direction * deltaTime;
          this.updateCardPosition();
          this.updateSpeedIndicator();
        }
        this.animationId = requestAnimationFrame(() => this.animate());
      }

      updateCardPosition() {
        const containerWidth = this.containerWidth;
        const cardLineWidth = this.cardLineWidth;
        if (this.position < -cardLineWidth) {
          this.position = containerWidth;
        } else if (this.position > containerWidth) {
          this.position = -cardLineWidth;
        }
        this.cardLine.style.transform = `translateX(${this.position}px)`;
        this.updateCardClipping();
      }

      updateSpeedIndicator() {
        if (this.speedIndicator) {
          this.speedIndicator.textContent = Math.round(this.velocity).toString();
        }
      }

      generateCode(width: number, height: number) {
        const randInt = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;
        const pick = (arr: string[]) => arr[randInt(0, arr.length - 1)];

        const library = [
          "// compiled preview • scanner demo", "const SCAN_WIDTH = 8;", "const FADE_ZONE = 35;",
          "const MAX_PARTICLES = 2500;", "const TRANSITION = 0.05;",
          "function clamp(n, a, b) { return Math.max(a, Math.min(b, n)); }",
          "class Particle { constructor(x, y) { this.x = x; this.y = y; } }",
          "const scanner = { x: Math.floor(window.innerWidth / 2), width: SCAN_WIDTH };"
        ];

        let flow = library.join(" ").replace(/\s+/g, " ").trim();
        const totalChars = width * height;
        while (flow.length < totalChars + width) {
          flow += " " + pick(library).replace(/\s+/g, " ").trim();
        }

        let out = "";
        let offset = 0;
        for (let row = 0; row < height; row++) {
          let line = flow.slice(offset, offset + width);
          if (line.length < width) line = line + " ".repeat(width - line.length);
          out += line + (row < height - 1 ? "\n" : "");
          offset += width;
        }
        return out;
      }

      createCardWrapper(index: number) {
        const wrapper = document.createElement("div");
        wrapper.className = "card-wrapper";
        const normalCard = document.createElement("div");
        normalCard.className = "card card-normal";
        const cardImages = [
          "https://cdn.prod.website-files.com/68789c86c8bc802d61932544/689f20b55e654d1341fb06f8_4.1.png",
          "https://cdn.prod.website-files.com/68789c86c8bc802d61932544/689f20b5a080a31ee7154b19_1.png",
          "https://cdn.prod.website-files.com/68789c86c8bc802d61932544/689f20b5c1e4919fd69672b8_3.png",
          "https://cdn.prod.website-files.com/68789c86c8bc802d61932544/689f20b5f6a5e232e7beb4be_2.png",
          "https://cdn.prod.website-files.com/68789c86c8bc802d61932544/689f20b5bea2f1b07392d936_4.png",
        ];
        const cardImage = document.createElement("img");
        cardImage.className = "card-image";
        cardImage.src = cardImages[index % cardImages.length];
        cardImage.draggable = false;
        normalCard.appendChild(cardImage);

        const asciiCard = document.createElement("div");
        asciiCard.className = "card card-ascii";
        const asciiContent = document.createElement("div");
        asciiContent.className = "ascii-content";
        asciiContent.textContent = this.generateCode(66, 19);
        asciiCard.appendChild(asciiContent);

        wrapper.appendChild(normalCard);
        wrapper.appendChild(asciiCard);
        return wrapper;
      }

      updateCardClipping() {
        const scannerX = window.innerWidth / 2;
        const scannerWidth = 8;
        const scannerLeft = scannerX - scannerWidth / 2;
        const scannerRight = scannerX + scannerWidth / 2;
        let anyScanningActive = false;

        const wrappers = this.cardLine.querySelectorAll(".card-wrapper");
        wrappers.forEach((el) => {
          const wrapper = el as HTMLElement;
          const rect = wrapper.getBoundingClientRect();
          const cardLeft = rect.left;
          const cardRight = rect.right;
          const cardWidth = rect.width;

          const normalCard = wrapper.querySelector(".card-normal") as HTMLElement;
          const asciiCard = wrapper.querySelector(".card-ascii") as HTMLElement;

          if (cardLeft < scannerRight && cardRight > scannerLeft) {
            anyScanningActive = true;
            const scannerIntersectLeft = Math.max(scannerLeft - cardLeft, 0);
            const scannerIntersectRight = Math.min(scannerRight - cardLeft, cardWidth);
            const normalClipRight = (scannerIntersectLeft / cardWidth) * 100;
            const asciiClipLeft = (scannerIntersectRight / cardWidth) * 100;
            normalCard.style.setProperty("--clip-right", `${normalClipRight}%`);
            asciiCard.style.setProperty("--clip-left", `${asciiClipLeft}%`);

            if (!wrapper.hasAttribute("data-scanned") && scannerIntersectLeft > 0) {
              wrapper.setAttribute("data-scanned", "true");
              const scanEffect = document.createElement("div");
              scanEffect.className = "scan-effect";
              wrapper.appendChild(scanEffect);
              setTimeout(() => scanEffect.remove(), 600);
            }
          } else {
            if (cardRight < scannerLeft) {
              normalCard.style.setProperty("--clip-right", "100%");
              asciiCard.style.setProperty("--clip-left", "100%");
            } else if (cardLeft > scannerRight) {
              normalCard.style.setProperty("--clip-right", "0%");
              asciiCard.style.setProperty("--clip-left", "0%");
            }
            wrapper.removeAttribute("data-scanned");
          }
        });
        if ((window as any).setScannerScanning) (window as any).setScannerScanning(anyScanningActive);
      }

      populateCardLine() {
        this.cardLine.innerHTML = "";
        for (let i = 0; i < 30; i++) this.cardLine.appendChild(this.createCardWrapper(i));
      }

      startPeriodicUpdates() {
        setInterval(() => {
          this.cardLine.querySelectorAll(".ascii-content").forEach(content => {
            if (Math.random() < 0.15) content.textContent = this.generateCode(66, 19);
          });
        }, 200);
      }

      destroy() {
        if (this.animationId) cancelAnimationFrame(this.animationId);
      }
    }

    class ParticleSystem {
      scene: any; camera: any; renderer: any; particles: any; particleCount = 400; canvas: HTMLCanvasElement;
      constructor(canvas: HTMLCanvasElement) {
        this.canvas = canvas;
        this.init();
      }
      init() {
        this.scene = new THREE.Scene();
        this.camera = new THREE.OrthographicCamera(-window.innerWidth/2, window.innerWidth/2, 125, -125, 1, 1000);
        this.camera.position.z = 100;
        this.renderer = new THREE.WebGLRenderer({ canvas: this.canvas, alpha: true, antialias: true });
        this.renderer.setSize(window.innerWidth, 250);
        this.createParticles();
        this.animate();
        window.addEventListener("resize", () => {
          this.camera.left = -window.innerWidth / 2;
          this.camera.right = window.innerWidth / 2;
          this.camera.updateProjectionMatrix();
          this.renderer.setSize(window.innerWidth, 250);
        });
      }
      createParticles() {
        const geometry = new THREE.BufferGeometry();
        const positions = new Float32Array(this.particleCount * 3);
        const alphas = new Float32Array(this.particleCount);
        const velocities = new Float32Array(this.particleCount);
        const canvas = document.createElement("canvas");
        canvas.width = 64; canvas.height = 64;
        const ctx = canvas.getContext("2d")!;
        const grad = ctx.createRadialGradient(32, 32, 0, 32, 32, 32);
        grad.addColorStop(0, "#fff"); grad.addColorStop(1, "transparent");
        ctx.fillStyle = grad; ctx.arc(32, 32, 32, 0, Math.PI*2); ctx.fill();
        const texture = new THREE.CanvasTexture(canvas);
        for (let i = 0; i < this.particleCount; i++) {
          positions[i*3] = (Math.random()-0.5)*window.innerWidth*2;
          positions[i*3+1] = (Math.random()-0.5)*250;
          alphas[i] = Math.random();
          velocities[i] = Math.random()*60 + 30;
        }
        geometry.setAttribute("position", new THREE.BufferAttribute(positions, 3));
        geometry.setAttribute("alpha", new THREE.BufferAttribute(alphas, 1));
        const material = new THREE.ShaderMaterial({
          uniforms: { pointTexture: { value: texture }, size: { value: 6.0 } },
          vertexShader: `attribute float alpha; varying float vAlpha; void main() { vAlpha = alpha; gl_PointSize = 6.0; gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0); }`,
          fragmentShader: `uniform sampler2D pointTexture; varying float vAlpha; void main() { gl_FragColor = vec4(1.0, 1.0, 1.0, vAlpha) * texture2D(pointTexture, gl_PointCoord); }`,
          transparent: true, blending: THREE.AdditiveBlending, depthWrite: false
        });
        this.particles = new THREE.Points(geometry, material);
        this.scene.add(this.particles);
        (this as any).velocities = velocities;
      }
      animate() {
        if (this.particles) {
          const positions = this.particles.geometry.attributes.position.array;
          const alphas = this.particles.geometry.attributes.alpha.array;
          for (let i = 0; i < this.particleCount; i++) {
            positions[i*3] += (this as any).velocities[i] * 0.016;
            if (positions[i*3] > window.innerWidth/2 + 100) positions[i*3] = -window.innerWidth/2 - 100;
            if (Math.random() < 0.05) alphas[i] = Math.random();
          }
          this.particles.geometry.attributes.position.needsUpdate = true;
          this.particles.geometry.attributes.alpha.needsUpdate = true;
        }
        this.renderer.render(this.scene, this.camera);
        requestAnimationFrame(() => this.animate());
      }
    }

    class ParticleScanner {
      canvas: HTMLCanvasElement; ctx: CanvasRenderingContext2D; w: number; h: number; scanningActive = false;
      constructor(canvas: HTMLCanvasElement) {
        this.canvas = canvas; this.ctx = canvas.getContext("2d")!;
        this.w = window.innerWidth; this.h = 300;
        this.init();
      }
      init() {
        this.canvas.width = this.w; this.canvas.height = this.h;
        this.animate();
        window.addEventListener("resize", () => { this.w = window.innerWidth; this.canvas.width = this.w; });
      }
      animate() {
        this.ctx.clearRect(0, 0, this.w, this.h);
        const x = this.w / 2;
        const grad = this.ctx.createLinearGradient(x - 10, 0, x + 10, 0);
        grad.addColorStop(0, "transparent");
        grad.addColorStop(0.5, this.scanningActive ? "rgba(212, 255, 0, 0.8)" : "rgba(255, 255, 255, 0.3)");
        grad.addColorStop(1, "transparent");
        this.ctx.fillStyle = grad;
        this.ctx.fillRect(x - 5, 0, 10, this.h);
        if (this.scanningActive) {
          this.ctx.shadowBlur = 15; this.ctx.shadowColor = "#D4FF00";
          this.ctx.fillStyle = "#D4FF00"; this.ctx.fillRect(x - 1, 0, 2, this.h);
          this.ctx.shadowBlur = 0;
        }
        requestAnimationFrame(() => this.animate());
      }
    }

    const scanner = new ParticleScanner(scannerCanvasRef.current);
    const stream = new CardStreamController(cardStreamRef.current, cardLineRef.current, speedValueRef.current);
    const particles = new ParticleSystem(particleCanvasRef.current);

    (window as any).setScannerScanning = (active: boolean) => scanner.scanningActive = active;

    return () => {
      stream.destroy();
    };
  }, []);

  return (
    <div className={`scanner-section-container ${hideText ? 'h-[400px]' : 'py-24'} group`}>
      {!hideText && (
        <div className="max-w-4xl mx-auto text-center mb-16 relative z-20">
          <h2 className="text-4xl md:text-7xl font-black mb-6 tracking-tight text-white">
            Stop Burning Cash on <br />
            <span className="text-[#D4FF00]">Bad Websites</span>
          </h2>
          <p className="text-gray-400 text-lg md:text-xl font-medium max-w-2xl mx-auto px-6">
            We scan your business and reveal the hidden code to high-converting websites—without the expensive trial and error.
          </p>
        </div>
      )}

      <div className="speed-indicator !top-[-40px] !right-0">
        Speed: <span id="speedValue" ref={speedValueRef}>120</span> px/s
      </div>

      <div className="relative w-full h-[300px] flex items-center justify-center" ref={containerRef}>
        <canvas id="particleCanvas" ref={particleCanvasRef} className="absolute inset-0 pointer-events-none"></canvas>
        <canvas id="scannerCanvas" ref={scannerCanvasRef} className="absolute inset-0 pointer-events-none z-[15]"></canvas>

        <div className="card-stream h-[250px] top-1/2 -translate-y-1/2" id="cardStream" ref={cardStreamRef}>
          <div className="card-line" id="cardLine" ref={cardLineRef}></div>
        </div>
      </div>
    </div>
  );
};

export default CardScannerSection;

